import { BrowserRouter, Routes, Route, Navigate, useLocation } from "react-router-dom";
import { Toaster } from "react-hot-toast";
import { AnimatePresence, motion } from "framer-motion";
import { AuthProvider, useAuth } from "./context/AuthContext";
import ThemeToggle from "./components/ThemeToggle";

// Core Pages
import LandingPage from "./pages/LandingPage";

// Auth pages
import LoginPage from "./pages/auth/LoginPage";
import RegisterPage from "./pages/auth/RegisterPage";

// Admin pages
import AdminDashboard from "./pages/admin/AdminDashboard";

// Teacher pages
import TeacherDashboard from "./pages/teacher/TeacherDashboard";
import CreateQuizPage from "./pages/teacher/CreateQuizPage";
import QuestionBankPage from "./pages/teacher/QuestionBankPage";
import TeacherAnalyticsPage from "./pages/teacher/TeacherAnalyticsPage";

// Student pages
import StudentDashboard from "./pages/student/StudentDashboard";
import QuizAttemptPage from "./pages/student/QuizAttemptPage";
import ResultPage from "./pages/student/ResultPage";
import StudentAnalyticsPage from "./pages/student/StudentAnalyticsPage";

function ProtectedRoute({ children, roles }) {
  const { user, loading } = useAuth();
  if (loading) return (
    <div className="flex items-center justify-center min-h-screen">
      <div className="relative">
        <div className="w-16 h-16 border-4 border-brand-violet/20 rounded-full" />
        <div className="absolute top-0 left-0 w-16 h-16 border-4 border-brand-violet border-t-transparent rounded-full animate-spin" />
      </div>
    </div>
  );
  if (!user) return <Navigate to="/login" replace />;
  if (roles && !roles.includes(user.role)) return <Navigate to="/" replace />;
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.98 }}
      animate={{ opacity: 1, scale: 1 }}
      exit={{ opacity: 0, scale: 1.02 }}
      transition={{ duration: 0.3 }}
      className="min-h-screen"
    >
      {children}
    </motion.div>
  );
}

function RoleRedirect() {
  const { user } = useAuth();
  if (!user) return <Navigate to="/login" replace />;
  if (user.role === "admin") return <Navigate to="/admin" replace />;
  if (user.role === "teacher") return <Navigate to="/teacher" replace />;
  return <Navigate to="/student" replace />;
}

function AnimatedRoutes() {
  const location = useLocation();
  return (
    <AnimatePresence mode="wait">
      <Routes location={location} key={location.pathname}>
        {/* Public */}
        <Route path="/" element={<LandingPage />} />
        <Route path="/login" element={<LoginPage />} />
        <Route path="/register" element={<RegisterPage />} />
        <Route path="/dashboard" element={<RoleRedirect />} />

        {/* Admin */}
        <Route path="/admin/*" element={
          <ProtectedRoute roles={["admin"]}>
            <AdminDashboard />
          </ProtectedRoute>
        } />

        {/* Teacher */}
        <Route path="/teacher" element={
          <ProtectedRoute roles={["teacher", "admin"]}>
            <TeacherDashboard />
          </ProtectedRoute>
        } />
        <Route path="/teacher/quiz/create" element={
          <ProtectedRoute roles={["teacher", "admin"]}>
            <CreateQuizPage />
          </ProtectedRoute>
        } />
        <Route path="/teacher/quiz/:quizId/edit" element={
          <ProtectedRoute roles={["teacher", "admin"]}>
            <CreateQuizPage />
          </ProtectedRoute>
        } />
        <Route path="/teacher/questions" element={
          <ProtectedRoute roles={["teacher", "admin"]}>
            <QuestionBankPage />
          </ProtectedRoute>
        } />
        <Route path="/teacher/analytics/:quizId" element={
          <ProtectedRoute roles={["teacher", "admin"]}>
            <TeacherAnalyticsPage />
          </ProtectedRoute>
        } />

        {/* Student */}
        <Route path="/student" element={
          <ProtectedRoute roles={["student", "admin"]}>
            <StudentDashboard />
          </ProtectedRoute>
        } />
        <Route path="/student/quiz/:quizId/attempt" element={
          <ProtectedRoute roles={["student", "admin"]}>
            <QuizAttemptPage />
          </ProtectedRoute>
        } />
        <Route path="/student/result/:attemptId" element={
          <ProtectedRoute roles={["student", "admin"]}>
            <ResultPage />
          </ProtectedRoute>
        } />
        <Route path="/student/analytics" element={
          <ProtectedRoute roles={["student", "admin"]}>
            <StudentAnalyticsPage />
          </ProtectedRoute>
        } />
      </Routes>
    </AnimatePresence>
  );
}

function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <div className="fixed top-6 right-6 z-[100]">
          <ThemeToggle />
        </div>
        <Toaster
          position="top-right"
          toastOptions={{
            style: {
              background: "var(--surface-color)",
              color: "var(--text-primary)",
              border: "1px solid var(--border-color)",
              borderRadius: "1rem",
              backdropFilter: "blur(10px)",
              padding: "1rem 1.5rem"
            },
          }}
        />
        <AnimatedRoutes />
      </BrowserRouter>
    </AuthProvider>
  );
}

export default App;

import Sidebar from "./Sidebar";
import Navbar from "./Navbar";
import { motion } from "framer-motion";

export default function DashboardLayout({ children }) {
    return (
        <div className="flex min-h-screen bg-bg-color overflow-hidden">
            {/* Background Decorative Glow */}
            <div className="fixed inset-0 overflow-hidden pointer-events-none -z-10">
                <div className="absolute top-[-10%] left-[-5%] w-[40%] h-[40%] bg-brand-violet/5 rounded-full blur-[120px]" />
                <div className="absolute bottom-[-10%] right-[-5%] w-[40%] h-[40%] bg-brand-cyan/5 rounded-full blur-[120px]" />
            </div>

            <Sidebar />

            <div className="flex-1 flex flex-col min-h-screen ml-20 lg:ml-[280px] transition-all duration-500 ease-in-out">
                <Navbar />
                <main className="flex-1 p-8 overflow-x-hidden">
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.5 }}
                    >
                        {children}
                    </motion.div>
                </main>
            </div>
        </div>
    );
}

import { useState, useEffect } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { motion, AnimatePresence } from "framer-motion";
import {
    Zap, LayoutDashboard, BookOpen, Database, BarChart2, Users,
    LogOut, ChevronLeft, ChevronRight, Trophy, Settings, Shield,
    ClipboardList, GraduationCap, Layout
} from "lucide-react";

const NAV_BY_ROLE = {
    admin: [
        { label: "Overview", icon: LayoutDashboard, path: "/admin" },
        { label: "User Management", icon: Users, path: "/admin/users" },
        { label: "System Analytics", icon: BarChart2, path: "/admin/analytics" },
    ],
    teacher: [
        { label: "Overview", icon: LayoutDashboard, path: "/teacher" },
        { label: "Quiz Lab", icon: BookOpen, path: "/teacher/quiz/create" },
        { label: "Questions", icon: Database, path: "/teacher/questions" },
        { label: "Analytics", icon: BarChart2, path: "/teacher/analytics" },
    ],
    student: [
        { label: "Overview", icon: LayoutDashboard, path: "/student" },
        { label: "Live Quizzes", icon: ClipboardList, path: "/student/quizzes" },
        { label: "Leaderboard", icon: Trophy, path: "/student/leaderboard" },
        { label: "My Stats", icon: BarChart2, path: "/student/analytics" },
    ],
};

export default function Sidebar() {
    const { user, logout } = useAuth();
    const location = useLocation();
    const navigate = useNavigate();
    const [collapsed, setCollapsed] = useState(false);

    const navItems = NAV_BY_ROLE[user?.role] || [];

    const handleLogout = () => {
        logout();
        navigate("/login");
    };

    const ROLE_THEME = {
        admin: "text-brand-oxford bg-brand-oxford/10 border-brand-oxford/20",
        teacher: "text-brand-oxford bg-brand-oxford/10 border-brand-oxford/20",
        student: "text-brand-oxford bg-brand-oxford/10 border-brand-oxford/20",
    };

    return (
        <motion.aside
            initial={false}
            animate={{ width: collapsed ? 80 : 280 }}
            className="fixed top-0 left-0 h-full bg-surface-color/80 backdrop-blur-xl border-r border-border-color flex flex-col z-40 transition-all duration-500 ease-in-out"
        >
            {/* Logo */}
            <div className={`flex items-center gap-4 px-6 h-20 border-b border-border-color/50 ${collapsed ? "justify-center px-0" : ""}`}>
                <div className="w-10 h-10 rounded-md bg-brand-oxford flex items-center justify-center flex-shrink-0 cursor-pointer transition-transform duration-300">
                    <Zap className="w-5 h-5 text-white fill-current" />
                </div>
                {!collapsed && (
                    <motion.div
                        initial={{ opacity: 0, x: -10 }}
                        animate={{ opacity: 1, x: 0 }}
                        className="flex flex-col"
                    >
                        <span className="font-bold text-text-primary text-xl leading-none tracking-tight">QuizAI</span>
                        <span className="text-[10px] font-bold text-brand-gold uppercase tracking-widest mt-0.5">Academic Edition</span>
                    </motion.div>
                )}
            </div>

            {/* Nav */}
            <nav className="flex-1 px-4 py-8 space-y-2 overflow-y-auto">
                <AnimatePresence>
                    {navItems.map(({ label, icon: Icon, path }) => {
                        const isActive = location.pathname === path || (path !== "/" + user?.role && location.pathname.startsWith(path));
                        return (
                            <Link
                                key={path}
                                to={path}
                                className={`flex items-center gap-3 px-4 py-3 rounded-md transition-all duration-300 group relative ${isActive
                                    ? "bg-brand-oxford/10 text-brand-oxford"
                                    : "text-text-secondary hover:bg-border-color/30 hover:text-text-primary"
                                    } ${collapsed ? "justify-center px-0" : ""}`}
                            >
                                <Icon className={`w-[20px] h-[20px] flex-shrink-0 transition-all duration-300 ${isActive ? "text-brand-oxford" : "group-hover:scale-110"
                                    }`} />
                                {!collapsed && (
                                    <motion.span
                                        initial={{ opacity: 0 }}
                                        animate={{ opacity: 1 }}
                                        className="text-sm font-black tracking-tight"
                                    >
                                        {label}
                                    </motion.span>
                                )}
                                {isActive && !collapsed && (
                                    <motion.div
                                        layoutId="active-pill"
                                        className="ml-auto w-1 h-4 rounded-full bg-brand-oxford"
                                    />
                                )}
                            </Link>
                        );
                    })}
                </AnimatePresence>
            </nav>

            {/* User section */}
            <div className={`px-4 py-6 border-t border-border-color/50 ${collapsed ? "flex flex-col items-center" : ""}`}>
                {!collapsed && (
                    <div className="flex items-center gap-3 px-4 py-4 rounded-2xl bg-bg-color border border-border-color mb-4 group cursor-pointer hover:border-brand-violet/50 transition-all duration-300">
                        <div className="w-10 h-10 rounded-xl bg-brand-violet flex items-center justify-center text-white font-black text-lg flex-shrink-0 shadow-neon">
                            {user?.full_name?.[0]?.toUpperCase()}
                        </div>
                        <div className="flex-1 min-w-0">
                            <p className="text-sm font-black text-text-primary truncate">{user?.full_name}</p>
                            <p className="text-[10px] font-black text-text-secondary uppercase tracking-widest flex items-center gap-1.5">
                                <Shield className="w-3 h-3 text-brand-violet" />
                                {user?.role}
                            </p>
                        </div>
                    </div>
                )}

                <button
                    onClick={handleLogout}
                    className={`flex items-center gap-3 px-4 py-3.5 rounded-2xl w-full text-text-secondary hover:text-red-500 hover:bg-red-500/10 transition-all duration-300 ${collapsed ? "justify-center px-0" : ""}`}
                >
                    <LogOut className="w-5 h-5 flex-shrink-0" />
                    {!collapsed && <span className="text-sm font-black">Sign Out</span>}
                </button>
            </div>

            {/* Collapse toggle */}
            <button
                onClick={() => setCollapsed(!collapsed)}
                className="absolute top-24 -right-4 w-8 h-8 rounded-md bg-surface-color border border-border-color text-text-secondary hover:text-brand-oxford flex items-center justify-center transition-all shadow-md z-50 hover:scale-110"
            >
                {collapsed ? <ChevronRight className="w-4 h-4" /> : <ChevronLeft className="w-4 h-4" />}
            </button>
        </motion.aside>
    );
}

import { motion } from "framer-motion";

export default function StatCard({
    icon: Icon,
    title,
    value,
    trend,
    color = "brand-oxford"
}) {
    return (
        <motion.div
            whileHover={{ y: -2, transition: { duration: 0.2 } }}
            className="card relative overflow-hidden flex flex-col justify-between"
        >
            <div className="flex items-start justify-between">
                <div className={`w-10 h-10 rounded-md bg-${color}/10 flex items-center justify-center text-${color} border border-${color}/20`}>
                    <Icon className="w-5 h-5" />
                </div>
                {trend && (
                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded ${trend.startsWith('+') ? 'text-green-600 bg-green-50' : 'text-red-600 bg-red-50'}`}>
                        {trend}
                    </span>
                )}
            </div>

            <div className="mt-4">
                <h3 className="text-[10px] font-bold text-text-secondary uppercase tracking-widest leading-none mb-1">{title}</h3>
                <p className="text-2xl font-bold text-text-primary tracking-tight">{value}</p>
            </div>

            {/* Minimal decorator */}
            <div className={`absolute top-0 right-0 w-1 h-full bg-${color}/20`} />
        </motion.div>
    );
}

