                        <p className="text-text-secondary text-lg font-medium">Built for the next generation of high-performers.</p>
                    </div>

                    <motion.div
                        variants={containerVariants}
                        initial="hidden"
                        whileInView="visible"
                        viewport={{ once: true }}
