                            desc="Deep insights into your topic-wise mastery levels."
                        />
                        <FeatureCard
                            icon={<Trophy className="w-8 h-8 text-brand-gold" />}
                            title="Leaderboards"
                            desc="Show off your skills and compete with friends."
                        />
                    </motion.div>
                </div>
            </section>
        </div>
    );
}

function FeatureCard({ icon, title, desc }) {
    return (
