import { Users, BookOpen, Activity, Shield, CheckCircle, XCircle, BarChart2 } from "lucide-react";
import toast from "react-hot-toast";

function StatCard({ icon: Icon, label, value, colorClass }) {
    return (
        <div className="card flex items-center gap-4 border-l-4" style={{ borderLeftColor: colorClass }}>
            <div className={`w-12 h-12 rounded-md flex items-center justify-center flex-shrink-0`} style={{ backgroundColor: colorClass + '20', color: colorClass }}>
                <Icon className="w-6 h-6" />
