function AdminHome() {
    const [stats, setStats] = useState(null);
    const [users, setUsers] = useState([]);
    const [pendingTeachers, setPendingTeachers] = useState([]);

    useEffect(() => {
        usersAPI.stats().then(r => setStats(r.data)).catch(() => { });
        usersAPI.list({ limit: 50 }).then(r => setUsers(r.data)).catch(() => { });
        usersAPI.list({ role: "teacher", is_approved: false }).then(r => setPendingTeachers(r.data)).catch(() => { });
    }, []);

    const approveTeacher = async (id) => {
        await usersAPI.approve(id);
        toast.success("Teacher approved!");
        setPendingTeachers(prev => prev.filter(t => t.id !== id));
        usersAPI.stats().then(r => setStats(r.data)).catch(() => { });
    };

    const toggleActive = async (id) => {
        await usersAPI.toggleActive(id);
        toast.success("User status updated");
        usersAPI.list({ limit: 50 }).then(r => setUsers(r.data)).catch(() => { });
    };

    return (
        <div className="space-y-6 animate-slide-up">
            {/* Stats */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard icon={Users} label="Total Users" value={stats?.total_users} colorClass="#002147" />
                <StatCard icon={Users} label="Students" value={stats?.total_students} colorClass="#004B23" />
                <StatCard icon={BookOpen} label="Quizzes" value={stats?.total_quizzes} colorClass="#D4AF37" />
                <StatCard icon={Activity} label="Total Attempts" value={stats?.total_attempts} colorClass="#990000" />
            </div>

            {/* Pending Teacher Approvals */}
            {pendingTeachers.length > 0 && (
                <div className="card">
                    <div className="flex items-center gap-2 mb-4">
                        <Shield className="w-5 h-5 text-brand-gold" />
                        <h3 className="font-bold text-text-primary">Pending Teacher Approvals ({pendingTeachers.length})</h3>
                    </div>
                    <div className="space-y-3">
                        {pendingTeachers.map(t => (
                            <div key={t.id} className="flex items-center justify-between p-3 rounded-md bg-brand-gold/5 border border-brand-gold/20">
                                <div>
                                    <p className="font-bold text-text-primary">{t.full_name}</p>
                                    <p className="text-sm text-text-secondary">{t.email}</p>
                                </div>
                                <button onClick={() => approveTeacher(t.id)} className="btn-success text-sm px-4 py-2">
                                    <CheckCircle className="w-4 h-4 inline mr-1" />Approve
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* All Users Table */}
            <div className="card p-0 overflow-hidden">
                <div className="p-6 pb-0">
                    <h3 className="font-bold text-text-primary mb-4 flex items-center gap-2 text-xl">
                        <Users className="w-6 h-6 text-brand-oxford" /> All Registered Users
                    </h3>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm">
                        <thead>
                            <tr className="border-b border-border-color bg-light-bg dark:bg-dark-surface/50">
                                <th className="text-left py-4 px-4 text-text-secondary font-bold uppercase tracking-wider text-[10px]">Name</th>
                                <th className="text-left py-4 px-4 text-text-secondary font-bold uppercase tracking-wider text-[10px]">Email</th>
                                <th className="text-left py-4 px-4 text-text-secondary font-bold uppercase tracking-wider text-[10px]">Role</th>
                                <th className="text-left py-4 px-4 text-text-secondary font-bold uppercase tracking-wider text-[10px]">Status</th>
                                <th className="text-left py-4 px-4 text-text-secondary font-bold uppercase tracking-wider text-[10px]">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {users.map(u => (
                                <tr key={u.id} className="border-b border-border-color hover:bg-light-bg dark:hover:bg-dark-surface/30 transition-colors">
                                    <td className="py-4 px-4 font-bold text-text-primary">{u.full_name}</td>
                                    <td className="py-4 px-4 text-text-secondary">{u.email}</td>
                                    <td className="py-3 px-3">
                                        <span className={`badge ${u.role === "admin" ? "badge-red" : u.role === "teacher" ? "badge-purple" : "badge-blue"}`}>
                                            {u.role}
                                        </span>
                                    </td>
                                    <td className="py-3 px-3">
                                        <span className={`badge ${u.is_active ? "badge-green" : "badge-red"}`}>
                                            {u.is_active ? "Active" : "Inactive"}
                                        </span>
                                    </td>
                                    <td className="py-3 px-3">
