    const handleSubmit = async (e) => {
        e.preventDefault();
        if (form.password.length < 6) { toast.error("Password must be at least 6 characters"); return; }
        setLoading(true);
        try {
            await register(form);
            toast.success(
                form.role === "teacher"
                    ? "Account created! Awaiting admin approval. 🎓"
                    : "Account created! Please sign in. 🎉"
            );
            navigate("/login");
