import { useState, useEffect, useRef, useCallback } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { attemptsAPI, quizzesAPI } from "../../api/client";
import { motion, AnimatePresence } from "framer-motion";
import {
    AlertTriangle, Clock, ChevronLeft, ChevronRight,
    Send, Flag, Zap, HelpCircle, ShieldAlert
} from "lucide-react";
import toast from "react-hot-toast";

function formatTime(secs) {
    const m = Math.floor(secs / 60);
    const s = secs % 60;
    return `${m.toString().padStart(2, "0")}:${s.toString().padStart(2, "0")}`;
}

export default function QuizAttemptPage() {
    const { quizId } = useParams();
    const navigate = useNavigate();
    const [quiz, setQuiz] = useState(null);
    const [attempt, setAttempt] = useState(null);
    const [questions, setQuestions] = useState([]);
    const [answers, setAnswers] = useState({});
    const [currentIdx, setCurrentIdx] = useState(0);
    const [timeLeft, setTimeLeft] = useState(null);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [warnings, setWarnings] = useState(0);
    const [direction, setDirection] = useState(0); // -1 for prev, 1 for next

    const timerRef = useRef(null);
    const startTimeRef = useRef({});

    useEffect(() => {
        const init = async () => {
            const [qr, ar] = await Promise.all([
                quizzesAPI.get(quizId),
                attemptsAPI.start(quizId),
            ]);
            setQuiz(qr.data);
            setAttempt(ar.data);
            setTimeLeft(qr.data.duration_minutes * 60);

            const qs = await attemptsAPI.getQuestions(ar.data.attempt_id);
            setQuestions(qs.data);
            startTimeRef.current[qs.data[0]?.id] = Date.now();
            setLoading(false);
        };
        init().catch(err => {
            toast.error(err.response?.data?.detail || "Could not start quiz");
            navigate("/student");
        });
    }, [quizId]);

    useEffect(() => {
        if (timeLeft === null || timeLeft <= 0 || submitting) return;
        timerRef.current = setTimeout(() => setTimeLeft(t => t - 1), 1000);
        return () => clearTimeout(timerRef.current);
    }, [timeLeft, submitting]);

    useEffect(() => {
        if (timeLeft === 0 && attempt && !submitting) {
            handleSubmit(true);
        }
    }, [timeLeft, attempt]);

    useEffect(() => {
        const handleVisibility = () => {
            if (document.hidden && attempt) {
                const newWarnings = warnings + 1;
                setWarnings(newWarnings);
                attemptsAPI.logAntiCheat({ attempt_id: attempt.attempt_id, event_type: "tab_switch", details: `Tab switch #${newWarnings}` });
                toast.error(`⚠️ Warning ${newWarnings}/3: Suspicious activity detected!`, {
                    style: { background: "#EF4444", color: "#FFF", fontWeight: "bold" }
                });
                if (newWarnings >= 3) {
                    handleSubmit(true);
                }
            }
        };
        document.addEventListener("visibilitychange", handleVisibility);
        return () => document.removeEventListener("visibilitychange", handleVisibility);
    }, [attempt, warnings]);

    const handleAnswer = async (questionId, option) => {
        setAnswers(prev => ({ ...prev, [questionId]: option }));
        if (attempt) {
            const timeTaken = Math.round((Date.now() - (startTimeRef.current[questionId] || Date.now())) / 1000);
            await attemptsAPI.saveAnswer({ attempt_id: attempt.attempt_id, question_id: questionId, selected_option: option, time_taken_seconds: timeTaken });
        }
    };

    const goTo = (idx) => {
        setDirection(idx > currentIdx ? 1 : -1);
        startTimeRef.current[questions[idx]?.id] = Date.now();
        setCurrentIdx(idx);
    };

    const handleSubmit = useCallback(async (auto = false) => {
        if (!attempt || submitting) return;
        if (!auto && !confirm("Ready to submit? Your results will be calculated immediately.")) return;
        setSubmitting(true);
        clearTimeout(timerRef.current);
        try {
            await attemptsAPI.submit(attempt.attempt_id);
            navigate(`/student/result/${attempt.attempt_id}`);
        } catch (e) {
            toast.error("Submission failed. Auto-saved answers are safe.");
            setSubmitting(false);
        }
    }, [attempt, submitting, navigate]);

    if (loading) return (
        <div className="min-h-screen bg-bg-color flex items-center justify-center p-10">
            <div className="text-center">
                <motion.div
                    animate={{ rotate: 360 }}
                    transition={{ repeat: Infinity, duration: 2, ease: "linear" }}
                    className="w-12 h-12 border-4 border-brand-oxford border-t-transparent rounded-full mx-auto mb-8"
                />
                <h2 className="text-2xl font-bold text-text-primary tracking-tight">Syncing Assessment...</h2>
                <p className="text-text-secondary font-medium mt-2">Preparing secure examination environment</p>
            </div>
        </div>
    );

    const currentQ = questions[currentIdx];
    const selectedOption = answers[currentQ?.id];
    const answeredCount = Object.keys(answers).length;
    const progress = (answeredCount / questions.length) * 100;
    const urgentTime = timeLeft !== null && timeLeft < 60;

    return (
        <div className="min-h-screen bg-bg-color flex flex-col font-sans">
            {/* Immersive Header */}
            <header className="fixed top-0 left-0 w-full h-24 bg-surface-color/80 backdrop-blur-xl border-b border-border-color z-50 flex flex-col">
                {/* Progress Bar Top */}
                <div className="h-1.5 w-full bg-light-bg dark:bg-dark-border overflow-hidden">
                    <motion.div
                        initial={{ width: 0 }}
                        animate={{ width: `${progress}%` }}
                        className="h-full bg-brand-oxford"
                    />
                </div>

                <div className="flex-1 flex items-center justify-between px-8">
                    <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-md bg-brand-oxford/10 flex items-center justify-center text-brand-oxford transition-all duration-300">
                            <Zap className="w-5 h-5 fill-current" />
                        </div>
                        <div>
                            <h3 className="text-sm font-bold text-text-primary uppercase tracking-widest leading-none mb-1">{quiz?.title}</h3>
                            <div className="flex items-center gap-2">
                                <p className="text-[10px] font-bold text-text-secondary uppercase tracking-widest">Question {currentIdx + 1} of {questions.length}</p>
                                <span className={`w-1.5 h-1.5 rounded-full ${urgentTime ? 'bg-brand-crimson animate-ping' : 'bg-brand-emerald'}`} />
                            </div>
                        </div>
                    </div>

                    <div className="flex items-center gap-8">
                        {/* Warnings */}
                        {warnings > 0 && (
                            <div className="hidden md:flex items-center gap-2 px-4 py-2 rounded-xl bg-red-500/10 border border-red-500/20 text-red-500 text-xs font-black uppercase tracking-widest">
                                <ShieldAlert className="w-4 h-4" />
                                Warn: {warnings}/3
                            </div>
                        )}

                        {/* Timer */}
                        <div className={`flex items-center gap-3 px-6 py-2.5 rounded-md font-bold text-lg tracking-tight transition-all duration-300 ${urgentTime
                            ? "bg-brand-crimson text-white animate-pulse"
                            : "bg-surface-color border border-border-color text-text-primary"
                            }`}>
                            <Clock className={`w-4 h-4 ${urgentTime ? "animate-spin-slow" : "text-brand-oxford"}`} />
                            {formatTime(timeLeft || 0)}
                        </div>

                        <button
                            onClick={() => handleSubmit(false)}
                            disabled={submitting}
                            className="btn-primary px-8 py-3.5 text-xs h-12"
                        >
                            {submitting ? "Processing..." : "Finish Attempt"}
                        </button>
                    </div>
                </div>
            </header>

            <main className="flex-1 flex flex-col lg:flex-row max-w-[1400px] mx-auto w-full gap-10 p-10 mt-24">
                {/* Question Area */}
                <div className="flex-1 flex flex-col">
                    <AnimatePresence mode="wait">
                        {currentQ && (
                            <motion.div
                                key={currentIdx}
                                initial={{ opacity: 0, x: direction * 50 }}
                                animate={{ opacity: 1, x: 0 }}
                                exit={{ opacity: 0, x: -direction * 50 }}
                                transition={{ duration: 0.4, ease: "circOut" }}
                                className="flex-1"
                            >
                                {/* Question Card */}
                                <div className="card p-10 mb-8 relative overflow-hidden group">
                                    <div className="absolute top-0 right-0 p-6">
                                        <div className={`px-4 py-1 rounded-full border text-[9px] font-bold uppercase tracking-widest ${currentQ.difficulty === 'hard' ? 'border-brand-crimson/30 text-brand-crimson' : 'border-brand-oxford/30 text-brand-oxford'
                                            }`}>
                                            {currentQ.difficulty || 'Medium'} Content
                                        </div>
                                    </div>

                                    <h2 className="text-2xl lg:text-3xl font-bold text-text-primary leading-tight mb-4 tracking-tight">
                                        {currentQ.text}
                                    </h2>
                                    <p className="text-[10px] font-bold text-text-secondary uppercase tracking-widest opacity-60">
                                        Weightage: {currentQ.marks} Points
                                    </p>
                                </div>

                                {/* Options Container */}
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {["a", "b", "c", "d"].map((opt) => {
                                        const optText = currentQ[`option_${opt}`];
                                        if (!optText) return null;
                                        const isSelected = selectedOption === opt;
                                        return (
                                            <motion.button
                                                key={opt}
                                                whileHover={{ y: -2 }}
                                                onClick={() => handleAnswer(currentQ.id, opt)}
                                                className={`flex items-center p-5 rounded-md border text-left transition-all duration-300 relative overflow-hidden group/opt ${isSelected
                                                    ? "border-brand-oxford bg-brand-oxford/5"
                                                    : "border-border-color bg-surface-color hover:border-brand-oxford/50"
                                                    }`}
                                            >
                                                <div className={`w-10 h-10 rounded-md flex items-center justify-center font-bold text-sm mr-6 transition-all shrink-0 ${isSelected ? "bg-brand-oxford text-white" : "bg-light-bg dark:bg-dark-border text-text-secondary group-hover/opt:text-brand-oxford"
                                                    }`}>
                                                    {opt.toUpperCase()}
                                                </div>
                                                <span className={`text-lg font-bold tracking-tight ${isSelected ? "text-brand-oxford" : "text-text-primary"}`}>
                                                    {optText}
                                                </span>
                                            </motion.button>
                                        );
                                    })}
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>

                    {/* Navigation Bar */}
                    <div className="flex items-center justify-between mt-12 bg-surface-color border border-border-color p-3 rounded-md shadow-sm">
                        <button
                            onClick={() => goTo(currentIdx - 1)}
                            disabled={currentIdx === 0}
                            className="bg-light-bg dark:bg-dark-border text-text-secondary px-6 py-3 rounded-md flex items-center gap-3 font-bold text-[10px] uppercase tracking-widest disabled:opacity-20 hover:text-brand-oxford transition-colors"
                        >
                            <ChevronLeft className="w-4 h-4" /> Previous
                        </button>
                        <div className="flex items-center gap-2">
                            {questions.map((_, i) => (
                                <div key={i} className={`h-1 rounded-full transition-all duration-300 ${i === currentIdx ? 'w-4 bg-brand-oxford' : answers[questions[i].id] ? 'w-2 bg-brand-gold' : 'w-2 bg-border-color'}`} />
                            ))}
                        </div>
                        <button
                            onClick={() => goTo(currentIdx + 1)}
                            disabled={currentIdx === questions.length - 1}
                            className="bg-light-bg dark:bg-dark-border text-text-secondary px-6 py-3 rounded-md flex items-center gap-3 font-bold text-[10px] uppercase tracking-widest disabled:opacity-20 hover:text-brand-oxford transition-colors"
                        >
                            Next <ChevronRight className="w-4 h-4" />
                        </button>
                    </div>
                </div>

                {/* Question Palette Sidebar */}
                <div className="w-full lg:w-80 flex-shrink-0">
                    <div className="card sticky top-32 p-8">
                        <div className="flex items-center justify-between mb-8">
                            <h4 className="text-[10px] font-bold text-text-secondary uppercase tracking-[0.2em]">Navigation Grid</h4>
                            <HelpCircle className="w-4 h-4 text-text-secondary opacity-40" />
                        </div>

                        <div className="grid grid-cols-5 gap-2.5">
                            {questions.map((q, i) => {
                                const isAnswered = !!answers[q.id];
                                const isCurrent = i === currentIdx;
                                return (
                                    <button
                                        key={q.id}
                                        onClick={() => goTo(i)}
                                        className={`w-10 h-10 rounded-md text-[10px] font-bold transition-all flex items-center justify-center relative ${isCurrent
                                            ? "bg-brand-oxford text-white scale-110"
                                            : isAnswered
                                                ? "bg-brand-gold/10 border border-brand-gold/30 text-brand-gold"
                                                : "bg-light-bg dark:bg-dark-border border border-border-color text-text-secondary hover:border-brand-oxford/50"
                                            }`}
                                    >
                                        {i + 1}
                                    </button>
                                );
                            })}
                        </div>

                        <div className="mt-10 space-y-4">
                            <h5 className="text-[10px] font-bold text-text-secondary uppercase tracking-widest pl-1">Legend</h5>
                            <div className="space-y-2">
                                <div className="flex items-center gap-3 text-[10px] font-bold text-text-primary px-3 py-2 rounded-md bg-light-bg dark:bg-dark-border border border-border-color">
                                    <div className="w-2.5 h-2.5 rounded bg-brand-oxford" />
                                    Active Question
                                </div>
                                <div className="flex items-center gap-3 text-[10px] font-bold text-text-primary px-3 py-2 rounded-md bg-light-bg dark:bg-dark-border border border-border-color">
                                    <div className="w-2.5 h-2.5 rounded bg-brand-gold/40 border border-brand-gold" />
                                    Answered
                                </div>
                                <div className="flex items-center gap-3 text-[10px] font-bold text-text-primary px-3 py-2 rounded-md bg-light-bg dark:bg-dark-border border border-border-color">
                                    <div className="w-2.5 h-2.5 rounded bg-border-color" />
                                    Pending
                                </div>
                            </div>
                        </div>

                        <div className="mt-10 pt-8 border-t border-border-color/50">
                            <div className="flex items-center justify-between mb-4 px-1">
                                <span className="text-[10px] font-bold text-text-secondary uppercase tracking-widest">Progress</span>
                                <span className="text-[10px] font-bold text-brand-oxford">{Math.round(progress)}%</span>
                            </div>
                            <div className="h-1.5 bg-light-bg dark:bg-dark-border rounded-full overflow-hidden">
                                <motion.div
                                    animate={{ width: `${progress}%` }}
                                    className="h-full rounded-full bg-brand-oxford"
                                />
                            </div>
                        </div>
                    </div>
                </div>
            </main>
        </div>
    );
}

import { useState, useEffect, useRef } from "react";
import { useParams, Link } from "react-router-dom";
import { attemptsAPI, aiAPI } from "../../api/client";
import { motion, AnimatePresence } from "framer-motion";
import {
    Trophy, CheckCircle, XCircle, Minus, Zap,
    ArrowRight, Lightbulb, ChevronDown, ChevronUp,
    Share2, RotateCcw, Home, BarChart3
} from "lucide-react";
import toast from "react-hot-toast";

const CATEGORY_CONFIG = {
    "Smart 🏆": { color: "from-brand-oxford to-brand-gold", bg: "bg-brand-gold/5 border-brand-gold/20", text: "text-brand-gold", emoji: "🏆" },
    "Good 🌟": { color: "from-brand-emerald to-brand-emerald/70", bg: "bg-brand-emerald/5 border-brand-emerald/20", text: "text-brand-emerald", emoji: "🌟" },
    "Average 📚": { color: "from-brand-oxford to-brand-oxford/70", bg: "bg-brand-oxford/5 border-brand-oxford/20", text: "text-brand-oxford", emoji: "📚" },
    "Weak 💪": { color: "from-brand-amber to-brand-amber/70", bg: "bg-brand-amber/5 border-brand-amber/20", text: "text-brand-amber", emoji: "💪" },
    "Poor 🔄": { color: "from-brand-crimson to-brand-crimson/70", bg: "bg-brand-crimson/5 border-brand-crimson/20", text: "text-brand-crimson", emoji: "🔄" },
};

function ConfettiEffect({ active }) {
    useEffect(() => {
        if (!active) return;
        import("canvas-confetti").then(m => {
            const confetti = m.default;
            const duration = 3 * 1000;
            const animationEnd = Date.now() + duration;
            const defaults = { startVelocity: 30, spread: 360, ticks: 60, zIndex: 0 };

            const randomInRange = (min, max) => Math.random() * (max - min) + min;

            const interval = setInterval(function () {
                const timeLeft = animationEnd - Date.now();
                if (timeLeft <= 0) return clearInterval(interval);
                const particleCount = 50 * (timeLeft / duration);
                confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.1, 0.3), y: Math.random() - 0.2 } });
                confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.7, 0.9), y: Math.random() - 0.2 } });
            }, 250);
        });
    }, [active]);
    return null;
}

export default function ResultPage() {
    const { attemptId } = useParams();
    const [result, setResult] = useState(null);
    const [loading, setLoading] = useState(true);
    const [expandedQ, setExpandedQ] = useState(null);
    const [explanations, setExplanations] = useState({});
    const [explainLoading, setExplainLoading] = useState({});

    useEffect(() => {
        attemptsAPI.result(attemptId).then(r => setResult(r.data)).finally(() => setLoading(false));
    }, [attemptId]);

    const getExplanation = async (answer) => {
        if (explanations[answer.question_id]) return;
        setExplainLoading(prev => ({ ...prev, [answer.question_id]: true }));
        try {
            const r = await aiAPI.explainMistake({
                question_text: answer.question_text,
                correct_option: answer.correct_option,
                correct_answer_text: answer[`option_${answer.correct_option}`],
                student_selected: answer.selected_option,
                student_answer_text: answer[`option_${answer.selected_option}`] || "Not answered",
            });
            setExplanations(prev => ({ ...prev, [answer.question_id]: r.data.explanation }));
        } catch {
            toast.error("AI is recharging. Try again in a moment.");
        } finally {
            setExplainLoading(prev => ({ ...prev, [answer.question_id]: false }));
        }
    };

    if (loading) return (
        <div className="min-h-screen bg-bg-color flex items-center justify-center">
            <motion.div
                animate={{ scale: [1, 1.1, 1] }}
                transition={{ repeat: Infinity, duration: 1.5 }}
                className="w-16 h-16 bg-brand-oxford/10 rounded-md border border-brand-oxford flex items-center justify-center"
            >
                <Trophy className="w-8 h-8 text-brand-oxford" />
            </motion.div>
        </div>
    );

    if (!result) return (
        <div className="min-h-screen bg-bg-color flex items-center justify-center text-text-secondary font-black uppercase tracking-widest">
            Identity Not Found
        </div>
    );

    const catConfig = CATEGORY_CONFIG[result.performance_category] || CATEGORY_CONFIG["Average 📚"];

    return (
        <div className="min-h-screen bg-bg-color selection:bg-brand-violet selection:text-white py-12 px-6">
            <ConfettiEffect active={result.percentage >= 75} />

            <div className="max-w-4xl mx-auto space-y-12 pb-20">
                {/* Score Showcase */}
                <motion.div
                    initial={{ opacity: 0, y: 30 }}
                    animate={{ opacity: 1, y: 0 }}
                    className={`card relative overflow-hidden text-center py-16 ${catConfig.bg}`}
                >
                    <div className="absolute top-0 inset-x-0 h-1 bg-gradient-to-r from-transparent via-current to-transparent opacity-10" />

                    <motion.div
                        initial={{ scale: 0.8 }}
                        animate={{ scale: 1 }}
                        className={`text-[10rem] font-bold leading-none bg-gradient-to-b ${catConfig.color} bg-clip-text text-transparent tracking-tighter mb-4`}
                    >
                        {Math.round(result.percentage)}%
                    </motion.div>

                    <div className={`inline-flex items-center gap-3 px-6 py-2 rounded-md bg-white dark:bg-slate-900 border border-current ${catConfig.text} font-bold text-lg tracking-tight uppercase mb-8 shadow-sm`}>
                        {result.performance_category}
                    </div>

                    <h2 className="text-2xl font-bold text-text-primary mb-2 tracking-tight">{result.quiz_title}</h2>
                    <p className="text-text-secondary font-medium">
                        {result.passed
                            ? "Performance threshold achieved. Excellent work."
                            : "Scope for improvement identified. Review the curriculum."
                        }
                    </p>
                </motion.div>

                {/* Reward & Progress Terminal */}
                <div className="grid md:grid-cols-2 gap-8">
                    <motion.div
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        className="card flex items-center gap-8 p-10 bg-brand-oxford/5 border-brand-oxford/10"
                    >
                        <div className="w-16 h-16 rounded-md bg-brand-oxford flex items-center justify-center shrink-0">
                            <Zap className="w-8 h-8 text-white fill-current" />
                        </div>
                        <div>
                            <p className="text-[10px] font-bold text-brand-oxford uppercase tracking-widest mb-1">XP EARNED</p>
                            <h3 className="text-4xl font-bold text-text-primary tracking-tighter">+{result.xp_earned}</h3>
                            <div className="mt-4 flex items-center gap-2">
                                <div className="h-1.5 flex-1 bg-light-bg dark:bg-dark-border rounded-full overflow-hidden">
                                    <motion.div
                                        initial={{ width: 0 }}
                                        animate={{ width: "65%" }}
                                        className="h-full bg-brand-oxford"
                                    />
                                </div>
                                <span className="text-[10px] font-bold text-text-secondary uppercase">Level 12</span>
                            </div>
                        </div>
                    </motion.div>

                    <motion.div
                        initial={{ opacity: 0, x: 20 }}
                        animate={{ opacity: 1, x: 0 }}
                        className="grid grid-cols-2 gap-4"
                    >
                        {[
                            { label: "Correct Answers", value: result.correct_count, icon: CheckCircle, color: "text-brand-emerald", bg: "bg-brand-emerald/5 border-brand-emerald/10" },
                            { label: "Points Scored", value: `${Math.round(result.score)}`, icon: BarChart3, color: "text-brand-oxford", bg: "bg-brand-oxford/5 border-brand-oxford/10" },
                        ].map((stat, i) => (
                            <div key={i} className={`card flex flex-col items-center justify-center p-6 border ${stat.bg}`}>
                                <stat.icon className={`w-8 h-8 ${stat.color} mb-3`} />
                                <span className="text-3xl font-bold text-text-primary tracking-tight">{stat.value}</span>
                                <span className="text-[10px] font-bold text-text-secondary uppercase tracking-widest mt-1">{stat.label}</span>
