                    </div>

                    <div className="space-y-4">
                        {(result.answers || []).map((a, i) => {
                            const isCorrect = a.is_correct;
                            const isUnattempted = !a.selected_option;
                            const isExpanded = expandedQ === a.question_id;

                            return (
                                <motion.div
                                    key={a.question_id}
                                    layout
                                    className={`card p-0 overflow-hidden border transition-all duration-300 ${isExpanded ? "border-brand-oxford/30 shadow-md" : "border-border-color hover:border-brand-oxford/20"
                                        }`}
                                >
                                    <button
                                        onClick={() => setExpandedQ(isExpanded ? null : a.question_id)}
                                        className="w-full text-left p-8 flex items-start gap-6 relative"
                                    >
                                        <div className={`w-10 h-10 rounded-md flex items-center justify-center shrink-0 ${isCorrect ? "bg-brand-emerald text-white" : "bg-brand-crimson text-white"
                                            }`}>
                                            {isCorrect ? <CheckCircle className="w-5 h-5" /> : <XCircle className="w-5 h-5" />}
                                        </div>
                                        <div className="flex-1 min-w-0 pr-8">
                                            <p className="text-lg font-bold text-text-primary leading-tight mb-2 pr-4">{a.question_text}</p>
                                            <div className="flex gap-3 items-center">
                                                <div className="px-3 py-0.5 bg-light-bg dark:bg-dark-border rounded-md border border-border-color text-[9px] font-bold uppercase text-brand-emerald tracking-wider">
                                                    Correct: {a.correct_option?.toUpperCase()}
                                                </div>
                                                {!isCorrect && (
                                                    <div className="px-3 py-0.5 bg-light-bg dark:bg-dark-border rounded-md border border-border-color text-[9px] font-bold uppercase text-brand-crimson tracking-wider">
                                                        Selected: {a.selected_option?.toUpperCase() || 'NA'}
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                        <div className="absolute top-8 right-8 text-text-secondary opacity-30">
                                            {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                                        </div>
                                    </button>

                                    <AnimatePresence>
                                        {isExpanded && (
                                            <motion.div
                                                initial={{ height: 0, opacity: 0 }}
                                                animate={{ height: "auto", opacity: 1 }}
                                                exit={{ height: 0, opacity: 0 }}
                                                className="bg-bg-color/50 border-t border-border-color px-8 py-10 space-y-8"
                                            >
                                                {/* Options Visualization */}
                                                <div className="grid md:grid-cols-2 gap-4">
                                                    {["a", "b", "c", "d"].map(opt => {
                                                        const isOptCorrect = a.correct_option === opt;
                                                        const isOptSelected = a.selected_option === opt;
                                                        return (
                                                            <div key={opt} className={`p-4 rounded-md border flex items-center gap-4 ${isOptCorrect
                                                                ? "bg-brand-emerald/10 border-brand-emerald/30 text-brand-emerald"
                                                                : isOptSelected
                                                                    ? "bg-brand-crimson/10 border-brand-crimson/30 text-brand-crimson"
                                                                    : "bg-surface-color/50 border-border-color/50 text-text-secondary"
                                                                }`}>
                                                                <span className="w-7 h-7 rounded bg-white dark:bg-slate-800 flex items-center justify-center font-bold text-xs shrink-0 border border-border-color">{opt.toUpperCase()}</span>
                                                                <span className="text-sm font-bold tracking-tight">{a[`option_${opt}`]}</span>
                                                            </div>
                                                        );
                                                    })}
                                                </div>

                                                {/* AI Insight section */}
                                                <div className="space-y-6">
                                                    {(a.explanation || explanations[a.question_id]) && (
                                                        <div className="card bg-brand-oxford/5 border-brand-oxford/10 p-8">
                                                            <div className="flex items-center gap-3 mb-4">
                                                                <Lightbulb className="w-5 h-5 text-brand-gold" />
                                                                <h4 className="text-[10px] font-bold text-brand-oxford uppercase tracking-widest">Pedagogical Insight</h4>
                                                            </div>
                                                            <p className="text-text-primary text-sm font-medium leading-relaxed">
                                                                {a.explanation || explanations[a.question_id]}
                                                            </p>
                                                        </div>
                                                    )}

                                                    {!isCorrect && !explanations[a.question_id] && (
                                                        <button
                                                            onClick={(e) => { e.stopPropagation(); getExplanation(a); }}
                                                            disabled={explainLoading[a.question_id]}
                                                            className="btn-secondary w-full flex items-center justify-center gap-3 py-4 text-xs group"
                                                        >
                                                            <Lightbulb className="w-4 h-4 text-brand-gold group-hover:scale-110 transition-transform" />
                                                            {explainLoading[a.question_id] ? "De-coding performance..." : "Generate AI Deep-Dive"}
                                                        </button>
                                                    )}
                                                </div>
                                            </motion.div>
                                        )}
                                    </AnimatePresence>
                                </motion.div>
                            );
                        })}
                    </div>
                </div>

                {/* Action Hub */}
                <div className="grid md:grid-cols-3 gap-6">
                    <Link to="/student" className="btn-secondary flex items-center justify-center gap-3 py-5 text-xs">
                        <Home className="w-4 h-4" /> Lab Center
                    </Link>
                    <Link to={`/student/quiz/${result.quiz_id}/attempt`} className="btn-secondary flex items-center justify-center gap-3 py-5 text-xs text-brand-indigo border-brand-indigo/30 hover:bg-brand-indigo/5">
                        <RotateCcw className="w-4 h-4" /> Reset Challenge
                    </Link>
                    <Link to="/student/analytics" className="btn-primary flex items-center justify-center gap-3 py-5 text-xs shadow-neon">
                        <BarChart3 className="w-4 h-4" /> Strategy Analytics
                    </Link>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from "react";
import DashboardLayout from "../../components/DashboardLayout";
import { analyticsAPI } from "../../api/client";
import {
    LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
    RadarChart, Radar, PolarGrid, PolarAngleAxis, PolarRadiusAxis, BarChart, Bar, Cell
} from "recharts";
import { TrendingUp, Target, Zap, BookOpen, Star, Trophy } from "lucide-react";

const PERF_COLORS = {
    "Strong 💪": "badge-green",
    "Weak 📖": "badge-red",
};

export default function StudentAnalyticsPage() {
    const [data, setData] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        analyticsAPI.studentMe().then(r => setData(r.data)).finally(() => setLoading(false));
    }, []);

    if (loading) return (
        <DashboardLayout>
            <div className="flex justify-center py-20"><div className="w-8 h-8 border-4 border-primary-500 border-t-transparent rounded-full animate-spin" /></div>
        </DashboardLayout>
    );

    const CATEGORY_MAP = [
        { range: "90-100%", label: "Smart 🏆", color: "#f59e0b" },
        { range: "75-89%", label: "Good 🌟", color: "#10b981" },
        { range: "60-74%", label: "Average 📚", color: "#3b82f6" },
        { range: "40-59%", label: "Weak 💪", color: "#f97316" },
        { range: "<40%", label: "Poor 🔄", color: "#ef4444" },
    ];

    const currentPct = data?.average_percentage || 0;
    const category = CATEGORY_MAP.find(c =>
        (c.label.startsWith("Smart") && currentPct >= 90) ||
        (c.label.startsWith("Good") && currentPct >= 75 && currentPct < 90) ||
        (c.label.startsWith("Average") && currentPct >= 60 && currentPct < 75) ||
        (c.label.startsWith("Weak") && currentPct >= 40 && currentPct < 60) ||
        (c.label.startsWith("Poor") && currentPct < 40)
    ) || CATEGORY_MAP[4];

    const trendData = (data?.performance_trend || []).map(t => ({
        date: t.date,
        score: t.percentage,
    }));

    const topicRadar = (data?.topic_analysis || []).slice(0, 6).map(t => ({
        topic: t.topic,
        accuracy: t.accuracy,
    }));

    const topicBar = (data?.topic_analysis || []).map(t => ({
        topic: t.topic,
        accuracy: t.accuracy,
        fill: t.accuracy >= 70 ? "#10b981" : t.accuracy >= 50 ? "#f59e0b" : "#ef4444",
    }));

    return (
        <DashboardLayout>
            <div className="space-y-6 animate-slide-up">
                {/* Performance category banner */}
                <div className="card py-6 text-center" style={{ background: `linear-gradient(135deg, ${category.color}15, transparent)`, borderColor: `${category.color}30` }}>
                    <div className="text-4xl font-black mb-2" style={{ color: category.color }}>
                        {data?.average_percentage?.toFixed(1) || 0}%
                    </div>
                    <p className="text-xl font-bold text-white">{category.label}</p>
                    <p className="text-gray-500 text-sm mt-1">Average across all {data?.total_attempts || 0} quizzes</p>
                </div>

                {/* Stats */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    {[
                        { icon: Trophy, label: "Best Score", value: `${data?.best_percentage?.toFixed(1) || 0}%`, color: "text-yellow-400" },
                        { icon: Target, label: "Accuracy", value: `${data?.accuracy?.toFixed(1) || 0}%`, color: "text-green-400" },
                        { icon: Zap, label: "Total XP", value: data?.total_xp || 0, color: "text-primary-400" },
                        { icon: Star, label: "Level", value: data?.level || 1, color: "text-violet-400" },
                    ].map(({ icon: Icon, label, value, color }) => (
                        <div key={label} className="card text-center py-5">
                            <Icon className={`w-7 h-7 ${color} mx-auto mb-2`} />
                            <p className="text-2xl font-bold text-white">{value}</p>
                            <p className="text-xs text-gray-500">{label}</p>
                        </div>
                    ))}
                </div>

                <div className="grid md:grid-cols-2 gap-6">
                    {/* Score Trend */}
                    <div className="card">
                        <h3 className="font-semibold text-white mb-4 flex items-center gap-2">
                            <TrendingUp className="w-5 h-5 text-primary-400" /> Performance Trend
                        </h3>
                        {trendData.length === 0 ? (
                            <div className="h-48 flex items-center justify-center text-gray-500 text-sm">No attempt data yet</div>
                        ) : (
                            <ResponsiveContainer width="100%" height={200}>
                                <LineChart data={trendData}>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
                                    <XAxis dataKey="date" tick={{ fill: "#9ca3af", fontSize: 10 }} />
                                    <YAxis domain={[0, 100]} tick={{ fill: "#9ca3af", fontSize: 10 }} unit="%" />
                                    <Tooltip contentStyle={{ background: "#1f2937", border: "1px solid #374151", borderRadius: "8px", color: "#f1f5f9" }} />
                                    <Line type="monotone" dataKey="score" stroke="#3b82f6" strokeWidth={2.5} dot={{ fill: "#3b82f6", r: 4 }} />
                                </LineChart>
                            </ResponsiveContainer>
                        )}
                    </div>

                    {/* Topic Radar */}
                    <div className="card">
                        <h3 className="font-semibold text-white mb-4 flex items-center gap-2">
                            <Target className="w-5 h-5 text-violet-400" /> Topic Mastery
                        </h3>
                        {topicRadar.length === 0 ? (
                            <div className="h-48 flex items-center justify-center text-gray-500 text-sm">Attempt tagged quizzes to see topic analysis</div>
                        ) : (
                            <ResponsiveContainer width="100%" height={200}>
                                <RadarChart data={topicRadar}>
                                    <PolarGrid stroke="#374151" />
                                    <PolarAngleAxis dataKey="topic" tick={{ fill: "#9ca3af", fontSize: 10 }} />
                                    <PolarRadiusAxis domain={[0, 100]} tick={{ fill: "#9ca3af", fontSize: 9 }} />
                                    <Radar dataKey="accuracy" stroke="#8b5cf6" fill="#8b5cf6" fillOpacity={0.3} strokeWidth={2} />
                                    <Tooltip contentStyle={{ background: "#1f2937", border: "1px solid #374151", borderRadius: "8px", color: "#f1f5f9" }} />
                                </RadarChart>
                            </ResponsiveContainer>
                        )}
                    </div>
                </div>

                {/* Topic Bar Chart */}
                {topicBar.length > 0 && (
                    <div className="card">
                        <h3 className="font-semibold text-white mb-4 flex items-center gap-2">
                            <BookOpen className="w-5 h-5 text-green-400" /> Topic-wise Accuracy
                        </h3>
                        <ResponsiveContainer width="100%" height={220}>
                            <BarChart data={topicBar}>
                                <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
                                <XAxis dataKey="topic" tick={{ fill: "#9ca3af", fontSize: 10 }} />
                                <YAxis domain={[0, 100]} tick={{ fill: "#9ca3af", fontSize: 10 }} unit="%" />
                                <Tooltip contentStyle={{ background: "#1f2937", border: "1px solid #374151", borderRadius: "8px", color: "#f1f5f9" }} />
                                <Bar dataKey="accuracy" radius={[4, 4, 0, 0]}>
                                    {topicBar.map((t, i) => <Cell key={i} fill={t.fill} />)}
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                )}

                {/* Weak / Strong topics */}
                {(data?.weak_topics?.length > 0 || data?.strong_topics?.length > 0) && (
                    <div className="grid md:grid-cols-2 gap-4">
                        {data?.weak_topics?.length > 0 && (
                            <div className="card border-l-4 border-l-red-500">
                                <h4 className="font-semibold text-red-300 mb-3 flex items-center gap-2">📖 Topics to Improve</h4>
                                <div className="space-y-2">
                                    {data.weak_topics.map(t => (
                                        <div key={t.topic} className="flex justify-between items-center">
                                            <span className="text-sm text-gray-300">{t.topic}</span>
                                            <span className="badge badge-red text-xs">{t.accuracy?.toFixed(1)}%</span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                        {data?.strong_topics?.length > 0 && (
                            <div className="card border-l-4 border-l-green-500">
                                <h4 className="font-semibold text-green-300 mb-3 flex items-center gap-2">💪 Strong Topics</h4>
                                <div className="space-y-2">
                                    {data.strong_topics.map(t => (
                                        <div key={t.topic} className="flex justify-between items-center">
                                            <span className="text-sm text-gray-300">{t.topic}</span>
                                            <span className="badge badge-green text-xs">{t.accuracy?.toFixed(1)}%</span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </DashboardLayout>
    );
}

