import { useState, useEffect } from "react";
import DashboardLayout from "../../components/DashboardLayout";
import { questionsAPI, quizzesAPI } from "../../api/client";
import { Search, Filter, Check, X, Trash2, Upload } from "lucide-react";
import toast from "react-hot-toast";

export default function QuestionBankPage() {
    const [questions, setQuestions] = useState([]);
    const [quizzes, setQuizzes] = useState([]);
    const [filters, setFilters] = useState({ topic: "", difficulty: "", is_approved: "" });
    const [loading, setLoading] = useState(true);

    const load = (f = filters) => {
        const params = {};
        if (f.topic) params.topic = f.topic;
        if (f.difficulty) params.difficulty = f.difficulty;
        if (f.is_approved !== "") params.is_approved = f.is_approved === "true";
        setLoading(true);
        questionsAPI.list(params).then(r => setQuestions(r.data)).finally(() => setLoading(false));
    };

    useEffect(() => {
        load();
        quizzesAPI.list().then(r => setQuizzes(r.data));
    }, []);

    const approve = async (id) => {
        await questionsAPI.update(id, { is_approved: true });
        setQuestions(prev => prev.map(q => q.id === id ? { ...q, is_approved: true } : q));
        toast.success("Question approved ✓");
    };

    const reject = async (id) => {
        await questionsAPI.delete(id);
        setQuestions(prev => prev.filter(q => q.id !== id));
        toast.success("Question removed");
    };

    const handleBulkImport = async (e, quizId) => {
        if (!quizId) { toast.error("Select a quiz first"); return; }
        const file = e.target.files[0];
        if (!file) return;
        try {
            const r = await questionsAPI.bulkImport(quizId, file);
            toast.success(`Imported ${r.data.imported} questions!`);
            load();
        } catch (err) {
            toast.error("Import failed");
        }
    };

    const [selectedQuizForImport, setSelectedQuizForImport] = useState("");

    return (
        <DashboardLayout>
            <div className="space-y-5 animate-slide-up">
                <div className="flex flex-wrap items-center justify-between gap-4">
                    <h2 className="text-xl font-bold text-white">Question Bank ({questions.length})</h2>
                    <div className="flex items-center gap-3">
                        <select className="input text-sm py-2" value={selectedQuizForImport} onChange={e => setSelectedQuizForImport(e.target.value)}>
                            <option value="">Select quiz for import…</option>
                            {quizzes.map(q => <option key={q.id} value={q.id}>{q.title}</option>)}
                        </select>
                        <label className="btn-secondary cursor-pointer flex items-center gap-2 text-sm py-2">
                            <Upload className="w-4 h-4" /> Import CSV/Excel
                            <input type="file" accept=".csv,.xlsx,.xls" className="hidden" onChange={e => handleBulkImport(e, selectedQuizForImport)} />
                        </label>
                    </div>
                </div>

                {/* Filters */}
                <div className="card flex flex-wrap gap-3 items-center py-4">
                    <Filter className="w-4 h-4 text-gray-500 flex-shrink-0" />
                    <input className="input text-sm py-2 w-48" placeholder="Filter by topic..." value={filters.topic}
                        onChange={e => setFilters({ ...filters, topic: e.target.value })} />
                    <select className="input text-sm py-2 w-36" value={filters.difficulty} onChange={e => setFilters({ ...filters, difficulty: e.target.value })}>
                        <option value="">All difficulty</option>
                        <option value="easy">Easy</option>
                        <option value="medium">Medium</option>
                        <option value="hard">Hard</option>
                    </select>
                    <select className="input text-sm py-2 w-36" value={filters.is_approved} onChange={e => setFilters({ ...filters, is_approved: e.target.value })}>
                        <option value="">All status</option>
                        <option value="true">Approved</option>
                        <option value="false">Pending</option>
                    </select>
                    <button onClick={() => load(filters)} className="btn-primary text-sm py-2 px-4 flex items-center gap-2">
                        <Search className="w-4 h-4" />Search
                    </button>
                </div>

                {/* Questions */}
                {loading ? (
                    <div className="flex justify-center py-12"><div className="w-8 h-8 border-4 border-primary-500 border-t-transparent rounded-full animate-spin" /></div>
                ) : (
                    <div className="space-y-3">
                        {questions.length === 0 ? (
                            <div className="card text-center py-12 text-gray-500">No questions found</div>
                        ) : questions.map((q, i) => (
                            <div key={q.id} className={`card border-l-4 ${q.is_approved ? "border-l-green-500" : "border-l-yellow-500"}`}>
                                <div className="flex items-start justify-between gap-3">
                                    <div className="flex-1 min-w-0">
                                        <p className="text-sm font-medium text-white">Q{i + 1}. {q.text}</p>
                                        <div className="grid grid-cols-2 gap-x-4 mt-2">
                                            {["a", "b", "c", "d"].map(opt => (
                                                <p key={opt} className={`text-xs py-0.5 ${q.correct_option === opt ? "text-green-400 font-semibold" : "text-gray-500"}`}>
                                                    ({opt.toUpperCase()}) {q[`option_${opt}`]}
                                                    {q.correct_option === opt && " ✓"}
                                                </p>
                                            ))}
                                        </div>
                                        <div className="flex gap-2 mt-2 flex-wrap">
                                            <span className={`badge ${q.difficulty === "easy" ? "badge-green" : q.difficulty === "hard" ? "badge-red" : "badge-yellow"}`}>{q.difficulty}</span>
                                            {q.topic && <span className="badge badge-blue">{q.topic}</span>}
                                            {q.is_ai_generated && <span className="badge badge-purple">AI Generated</span>}
                                            <span className={`badge ${q.is_approved ? "badge-green" : "badge-yellow"}`}>{q.is_approved ? "Approved" : "Pending"}</span>
                                        </div>
                                    </div>
                                    <div className="flex gap-2 flex-shrink-0">
                                        {!q.is_approved && (
                                            <button onClick={() => approve(q.id)} className="w-8 h-8 rounded-lg bg-green-500/10 border border-green-500/30 text-green-400 hover:bg-green-500/20 transition-all flex items-center justify-center">
                                                <Check className="w-4 h-4" />
                                            </button>
                                        )}
                                        <button onClick={() => reject(q.id)} className="w-8 h-8 rounded-lg bg-red-500/10 border border-red-500/30 text-red-400 hover:bg-red-500/20 transition-all flex items-center justify-center">
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </DashboardLayout>
    );
}

import { useState, useEffect } from "react";
import { useParams } from "react-router-dom";
import DashboardLayout from "../../components/DashboardLayout";
import { analyticsAPI } from "../../api/client";
import {
    BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
    PieChart, Pie, Cell, LineChart, Line, Legend
} from "recharts";
import { Trophy, Target, Users, TrendingUp } from "lucide-react";

const COLORS = ["#3b82f6", "#8b5cf6", "#10b981", "#f59e0b", "#ef4444"];

export default function TeacherAnalyticsPage() {
    const { quizId } = useParams();
    const [data, setData] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        analyticsAPI.quizStats(quizId).then(r => setData(r.data)).finally(() => setLoading(false));
    }, [quizId]);

    if (loading) return (
        <DashboardLayout>
            <div className="flex justify-center py-20"><div className="w-8 h-8 border-4 border-primary-500 border-t-transparent rounded-full animate-spin" /></div>
        </DashboardLayout>
    );

    if (!data || data.error) return (
        <DashboardLayout><div className="card text-center py-12 text-gray-500">No analytics data yet</div></DashboardLayout>
    );

    const distData = Object.entries(data.score_distribution || {}).map(([range, count]) => ({ range, count }));
    const qSuccessData = (data.question_stats || []).slice(0, 10).map(q => ({
        name: q.question_text?.slice(0, 20) + "…",
        rate: q.success_rate,
    }));

    return (
        <DashboardLayout>
            <div className="space-y-6 animate-slide-up">
                <h2 className="text-xl font-bold text-white">{data.quiz_title} — Analytics</h2>

                {/* Stats */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    {[
                        { icon: Users, label: "Total Attempts", value: data.total_attempts, color: "from-blue-500 to-cyan-600" },
                        { icon: Target, label: "Avg Score", value: `${data.average_percentage?.toFixed(1)}%`, color: "from-violet-500 to-purple-600" },
                        { icon: Trophy, label: "Highest", value: `${data.highest_score?.toFixed(1)}%`, color: "from-green-500 to-emerald-600" },
                        { icon: TrendingUp, label: "Pass Rate", value: `${data.pass_rate?.toFixed(1)}%`, color: "from-orange-500 to-red-600" },
                    ].map(({ icon: Icon, label, value, color }) => (
                        <div key={label} className="card flex items-center gap-3">
                            <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${color} flex items-center justify-center flex-shrink-0`}>
                                <Icon className="w-5 h-5 text-white" />
                            </div>
                            <div>
                                <p className="text-xl font-bold text-white">{value}</p>
                                <p className="text-xs text-gray-500">{label}</p>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="grid md:grid-cols-2 gap-6">
                    {/* Score Distribution */}
                    <div className="card">
                        <h3 className="font-semibold text-white mb-4">Score Distribution</h3>
                        <ResponsiveContainer width="100%" height={200}>
                            <BarChart data={distData}>
                                <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
                                <XAxis dataKey="range" tick={{ fill: "#9ca3af", fontSize: 11 }} />
                                <YAxis tick={{ fill: "#9ca3af", fontSize: 11 }} />
                                <Tooltip contentStyle={{ background: "#1f2937", border: "1px solid #374151", borderRadius: "8px", color: "#f1f5f9" }} />
                                <Bar dataKey="count" fill="url(#blueGrad)" radius={[4, 4, 0, 0]} />
                                <defs>
                                    <linearGradient id="blueGrad" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="0%" stopColor="#3b82f6" />
                                        <stop offset="100%" stopColor="#8b5cf6" />
                                    </linearGradient>
                                </defs>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>

                    {/* Question Success Rates */}
                    <div className="card">
                        <h3 className="font-semibold text-white mb-4">Hardest Questions (by success rate)</h3>
                        <ResponsiveContainer width="100%" height={200}>
                            <BarChart data={qSuccessData} layout="vertical">
                                <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
                                <XAxis type="number" domain={[0, 100]} tick={{ fill: "#9ca3af", fontSize: 11 }} unit="%" />
                                <YAxis dataKey="name" type="category" width={80} tick={{ fill: "#9ca3af", fontSize: 9 }} />
                                <Tooltip contentStyle={{ background: "#1f2937", border: "1px solid #374151", borderRadius: "8px", color: "#f1f5f9" }} />
                                <Bar dataKey="rate" fill="#10b981" radius={[0, 4, 4, 0]} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Leaderboard */}
                <div className="card">
                    <h3 className="font-semibold text-white mb-4 flex items-center gap-2">
                        <Trophy className="w-5 h-5 text-yellow-400" /> Class Leaderboard
                    </h3>
                    <div className="space-y-3">
                        {(data.leaderboard || []).map(s => (
                            <div key={s.rank} className="flex items-center gap-4 p-3 rounded-xl bg-gray-800/30 hover:bg-gray-800/50 transition-all">
                                <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm ${s.rank === 1 ? "bg-yellow-500 text-black" : s.rank === 2 ? "bg-gray-400 text-black" : s.rank === 3 ? "bg-amber-700 text-white" : "bg-gray-700 text-gray-300"}`}>
                                    {s.rank}
                                </div>
                                <div className="flex-1">
                                    <p className="font-medium text-white text-sm">{s.student_name}</p>
                                    <p className="text-xs text-gray-500">Time: {Math.round((s.time_taken_seconds || 0) / 60)}m {(s.time_taken_seconds || 0) % 60}s</p>
                                </div>
                                <div className="text-right">
                                    <p className="font-bold text-primary-300">{s.percentage?.toFixed(1)}%</p>
                                    <p className="text-xs text-gray-500">Score: {s.score}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </DashboardLayout>
    );
}

import { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import DashboardLayout from "../../components/DashboardLayout";
import StatCard from "../../components/StatCard";
import { quizzesAPI, analyticsAPI } from "../../api/client";
import { motion } from "framer-motion";
import {
    Plus, BookOpen, Users, BarChart2, Eye,
    Trash2, Globe, Lock, Edit, MoreHorizontal,
    TrendingUp, ShieldCheck, Share2, Layers
} from "lucide-react";
import toast from "react-hot-toast";

const DIFF_COLORS = {
    easy: "text-green-500 bg-green-500/10 border-green-500/20",
    medium: "text-brand-amber bg-brand-amber/10 border-brand-amber/20",
    hard: "text-red-500 bg-red-500/10 border-red-500/20"
};

export default function TeacherDashboard() {
    const [quizzes, setQuizzes] = useState([]);
    const [overview, setOverview] = useState(null);
    const [loading, setLoading] = useState(true);
    const navigate = useNavigate();

    useEffect(() => {
        Promise.all([
            quizzesAPI.list().then(r => setQuizzes(r.data)),
            analyticsAPI.teacherOverview().then(r => setOverview(r.data)),
        ]).finally(() => setLoading(false));
    }, []);

    const publishToggle = async (quiz) => {
        await quizzesAPI.publish(quiz.id);
        toast.success(quiz.is_published ? "Quiz unpublished" : "Quiz published! 🚀");
        quizzesAPI.list().then(r => setQuizzes(r.data));
    };

    const deleteQuiz = async (id) => {
        if (!confirm("Delete this quiz?")) return;
        await quizzesAPI.delete(id);
        toast.success("Quiz deleted");
        setQuizzes(prev => prev.filter(q => q.id !== id));
    };

    const containerVariants = {
        hidden: { opacity: 0 },
        visible: {
            opacity: 1,
            transition: { staggerChildren: 0.1 }
        }
    };

    const itemVariants = {
        hidden: { opacity: 0, y: 20 },
        visible: { opacity: 1, y: 0 }
    };

    return (
        <DashboardLayout>
            <div className="space-y-10 pb-12">
                {/* Header & Quick Action */}
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <div>
                        <h2 className="text-4xl font-black text-text-primary tracking-tight leading-none mb-2">Quiz Lab</h2>
                        <p className="text-text-secondary font-medium">Manage your assessments and track student progress.</p>
                    </div>
                    <Link to="/teacher/quiz/create" className="btn-primary flex items-center gap-3 px-6 py-4 rounded-md shadow-sm transition-transform hover:scale-105 active:scale-95">
                        <Plus className="w-5 h-5 flex-shrink-0" />
                        <span className="font-bold text-sm uppercase tracking-widest leading-none">Create New Quiz</span>
                    </Link>
                </div>

                {/* Stats Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    <StatCard
                        icon={Layers}
                        title="Total Quizzes"
                        value={overview?.total_quizzes ?? 0}
                        trend="+2 this month"
                        color="brand-oxford"
                    />
                    <StatCard
                        icon={ShieldCheck}
                        title="Published"
                        value={overview?.published_quizzes ?? 0}
                        trend="80% Live"
                        color="brand-sky"
                    />
                    <StatCard
                        icon={Users}
                        title="Student Attempts"
                        value={overview?.total_attempts ?? 0}
                        trend="+42% growth"
                        color="brand-emerald"
                    />
                    <StatCard
                        icon={TrendingUp}
                        title="Avg Pass Rate"
                        value="74%"
                        trend="Improving"
                        color="brand-gold"
                    />
                </div>

                {/* Content Section */}
                <div className="space-y-6">
                    <div className="flex items-center justify-between border-b border-border-color pb-6">
                        <h3 className="text-2xl font-black text-text-primary tracking-tight">Your Assessments</h3>
                        <div className="flex items-center gap-4">
                            <button className="text-[10px] font-bold uppercase tracking-[0.2em] text-text-secondary hover:text-brand-oxford px-3 py-1.5 rounded-md hover:bg-brand-oxford/5 transition-all">All</button>
                            <button className="text-[10px] font-bold uppercase tracking-[0.2em] text-text-secondary hover:text-brand-oxford px-3 py-1.5 rounded-md hover:bg-brand-oxford/5 transition-all">Live</button>
                            <button className="text-[10px] font-bold uppercase tracking-[0.2em] text-text-secondary hover:text-brand-oxford px-3 py-1.5 rounded-md hover:bg-brand-oxford/5 transition-all">Drafts</button>
                        </div>
                    </div>

                    {loading ? (
                        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                            {[1, 2, 3].map(i => (
                                <div key={i} className="h-64 rounded-md bg-surface-color animate-pulse border border-border-color" />
                            ))}
                        </div>
                    ) : quizzes.length === 0 ? (
                        <div className="card-premium flex flex-col items-center justify-center py-24 text-center">
                            <BookOpen className="w-16 h-16 text-text-secondary opacity-40 mb-4" />
                            <h4 className="text-xl font-black text-text-primary">No quizzes yet</h4>
                            <p className="text-text-secondary font-medium mt-2 mb-8">Ready to create your first assessment challenge?</p>
                            <Link to="/teacher/quiz/create" className="btn-secondary px-8 py-4 text-xs">
                                Jump to Designer
                            </Link>
                        </div>
                    ) : (
                        <motion.div
                            variants={containerVariants}
                            initial="hidden"
                            animate="visible"
                            className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6"
                        >
                            {quizzes.map(quiz => (
                                <motion.div
                                    key={quiz.id}
                                    variants={itemVariants}
                                    className="card p-0 flex flex-col group overflow-hidden border-t-4 border-t-brand-oxford shadow-md hover:shadow-lg transition-shadow"
                                >
                                    {/* Header Section */}
                                    <div className="p-8 pb-0">
                                        <div className="flex justify-between items-start mb-6">
                                            <div className="flex items-center gap-2">
                                                <div className={`w-2.5 h-2.5 rounded-full ${quiz.is_published ? "bg-green-600" : "bg-brand-gold"}`} />
                                                <span className={`text-[10px] font-bold uppercase tracking-widest ${quiz.is_published ? "text-green-600" : "text-brand-gold"}`}>
                                                    {quiz.is_published ? "Live" : "Draft"}
                                                </span>
                                            </div>
                                            <button className="text-text-secondary hover:text-brand-oxford transition-colors">
                                                <MoreHorizontal className="w-5 h-5" />
                                            </button>
                                        </div>

                                        <h4 className="text-2xl font-black text-text-primary mb-2 line-clamp-1 leading-tight group-hover:text-brand-violet transition-colors">{quiz.title}</h4>
                                        <p className="text-text-secondary text-sm font-medium h-5 mb-6">{quiz.subject || "No Subject"}</p>

                                        <div className="flex flex-wrap gap-2 mb-8">
                                            <span className={`px-2.5 py-0.5 rounded border text-[10px] font-bold uppercase tracking-widest ${DIFF_COLORS[quiz.difficulty] || "border-border-color text-text-secondary"}`}>
                                                {quiz.difficulty}
                                            </span>
                                            <span className="px-2.5 py-0.5 rounded border border-border-color text-text-secondary text-[10px] font-bold uppercase tracking-widest flex items-center gap-1.5">
                                                <Clock className="w-3 h-3" />
                                                {quiz.duration_minutes}m
                                            </span>
                                        </div>
                                    </div>

                                    {/* Management Actions */}
                                    <div className="grid grid-cols-4 gap-[1px] bg-border-color/50 mt-auto border-t border-border-color/50">
                                        <button
                                            onClick={() => publishToggle(quiz)}
                                            title={quiz.is_published ? "Unpublish Quiz" : "Publish Quiz"}
                                            className="bg-surface-color py-5 flex items-center justify-center text-text-secondary hover:text-brand-violet hover:bg-brand-violet/5 transition-all duration-300"
                                        >
                                            {quiz.is_published ? <Lock className="w-5 h-5" /> : <Globe className="w-5 h-5" />}
                                        </button>
                                        <Link
                                            to={`/teacher/analytics/${quiz.id}`}
                                            title="View Analytics"
                                            className="bg-surface-color py-5 flex items-center justify-center text-text-secondary hover:text-brand-cyan hover:bg-brand-cyan/5 transition-all duration-300"
                                        >
                                            <BarChart2 className="w-5 h-5" />
                                        </Link>
                                        <Link
                                            to={`/teacher/quiz/${quiz.id}/edit`}
                                            title="Edit Quiz"
                                            className="bg-surface-color py-5 flex items-center justify-center text-text-secondary hover:text-brand-indigo hover:bg-brand-indigo/5 transition-all duration-300"
                                        >
                                            <Edit className="w-5 h-5" />
                                        </Link>
                                        <button
                                            onClick={() => deleteQuiz(quiz.id)}
                                            title="Delete Quiz"
                                            className="bg-surface-color py-5 flex items-center justify-center text-text-secondary hover:text-red-500 hover:bg-red-500/5 transition-all duration-300"
                                        >
                                            <Trash2 className="w-5 h-5" />
                                        </button>
                                    </div>
                                </motion.div>
                            ))}
                        </motion.div>
                    )}
                </div>
            </div>
        </DashboardLayout>
    );
}
